--
-- Table structure for table `player_team_membership`
--

DROP TABLE IF EXISTS `player_team_membership`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `player_team_membership` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `player_id` int(11) NOT NULL COMMENT 'FK player',
  `team_id` int(11) NOT NULL COMMENT 'FK team',
  `from_date` date DEFAULT NULL COMMENT 'Début (NULL si inconnu)',
  `to_date` date DEFAULT NULL COMMENT 'Fin (NULL = en cours / inconnu)',
  `is_current` tinyint(1) NOT NULL DEFAULT 0 COMMENT '1 = club actuel (règle forte)' CHECK (`is_current` in (0,1)),
  `source_note` varchar(200) DEFAULT NULL COMMENT 'Source / note',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_pcm_exact` (`player_id`,`team_id`,`from_date`,`to_date`),
  KEY `ix_pcm_player_current` (`player_id`,`is_current`),
  KEY `ix_pcm_player_period` (`player_id`,`from_date`,`to_date`),
  KEY `ix_pcm_team_period` (`team_id`,`from_date`,`to_date`),
  KEY `ix_ptm_player_current` (`player_id`,`is_current`),
  KEY `ix_ptm_player_from_to` (`player_id`,`from_date`,`to_date`),
  KEY `ix_ptm_player_to_from` (`player_id`,`to_date`,`from_date`),
  KEY `ix_ptm_team_from_to` (`team_id`,`from_date`,`to_date`),
  CONSTRAINT `fk_pcm_player_id` FOREIGN KEY (`player_id`) REFERENCES `player` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_pcm_team_id` FOREIGN KEY (`team_id`) REFERENCES `team` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ck_pcm_dates` CHECK (`from_date` is null or `to_date` is null or `from_date` <= `to_date`)
) ENGINE=InnoDB AUTO_INCREMENT=2576 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

